using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ──────────────────────────────────────────────
    // CalculateTotal – DataRow (compile-time constants)
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.10, 0.00, DisplayName = "Zero unit price")]
    [DataRow(99.99, 0, 0.20, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "Maximum tax rate (100%)")]
    public void CalculateTotal_WithDataRow_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ──────────────────────────────────────────────
    // CalculateTotal – DynamicData (decimal precision)
    // ──────────────────────────────────────────────

    public static IEnumerable<object[]> CalculateTotalCases
    {
        get
        {
            yield return [19.99m, 4, 0.07m, 85.5572m, "Realistic retail scenario"];
            yield return [0.01m, 1, 0.0m, 0.01m, "Minimum non-zero price"];
            yield return [999.99m, 100, 0.25m, 124998.75m, "Large order with tax"];
            yield return [0.0m, 0, 0.0m, 0.0m, "All zeros"];
        }
    }

    [TestMethod]
    [DynamicData(nameof(CalculateTotalCases))]
    public void CalculateTotal_WithDynamicData_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected, string scenario)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result, $"Failed for: {scenario}");
    }

    // ──────────────────────────────────────────────
    // CalculateTotal – invalid arguments
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price")]
    public void CalculateTotal_NegativeUnitPrice_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity")]
    public void CalculateTotal_NegativeQuantity_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below zero")]
    [DataRow(10.00, 1, 1.01, DisplayName = "Tax rate above one")]
    public void CalculateTotal_InvalidTaxRate_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // ──────────────────────────────────────────────
    // ApplyDiscount – DataRow
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% off")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% off (free)")]
    [DataRow(49.99, 25.0, 37.4925, DisplayName = "Fractional result")]
    [DataRow(0.00, 50.0, 0.00, DisplayName = "Zero price with discount")]
    public void ApplyDiscount_WithDataRow_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ──────────────────────────────────────────────
    // ApplyDiscount – DynamicData (method source)
    // ──────────────────────────────────────────────

    public static IEnumerable<object[]> InvalidDiscountCases()
    {
        yield return [-0.01m, "Discount below zero"];
        yield return [100.01m, "Discount above 100"];
        yield return [-50m, "Large negative discount"];
        yield return [200m, "Discount far above 100"];
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_InvalidDiscount_Throws(decimal discountPercent, string scenario)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName, $"Wrong param for: {scenario}");
    }

    // ──────────────────────────────────────────────
    // FormatPrice – DataRow
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "Default dollar symbol")]
    [DataRow(19.99, "€", "€19.99", DisplayName = "Euro symbol")]
    [DataRow(0.00, "$", "$0.00", DisplayName = "Zero price")]
    [DataRow(1234.5, "£", "£1234.50", DisplayName = "Pads to two decimals")]
    [DataRow(9.999, "$", "$10.00", DisplayName = "Rounds up")]
    public void FormatPrice_WithSymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPrice_DefaultSymbol_UsesDollarSign()
    {
        var result = _calculator.FormatPrice(42.00m);

        Assert.AreEqual("$42.00", result);
    }
}

